name = "clawpier"
version = "0.4.1"
description = "OpenClaw Manager - Manage sandboxed OpenClaw bot instances"
authors = ["Runchao Han"]
edition = "2021"

[lib]
name = "clawpier_lib"
crate-type = ["lib", "cdylib", "staticlib"]

[build-dependencies]
tauri-build = { version = "2", features = [] }

[dependencies]
tauri = { version = "2", features = [] }
